Here's a complete example of data-driven MSTest tests for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline test cases ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double price, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)price);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.10, 90.00)]   // 10% off
    [DataRow(100.00, 0.00, 100.00)]  // no discount
    [DataRow(50.00, 0.50, 25.00)]    // half off
    [DataRow(200.00, 1.00, 0.00)]    // 100% off
    public void ApplyDiscount_ReturnsExpected(double total, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)total, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/reusable test cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_DynamicCases(int quantity, decimal price, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, price);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountEdgeCases), DynamicDataSourceType.Property)]
    public void ApplyDiscount_EdgeCases(decimal total, decimal discount, decimal expected)
    {
        var result = _calculator.ApplyDiscount(total, discount);
        Assert.AreEqual(expected, result);
    }

    // DynamicData source as a method
    private static IEnumerable<object[]> CalculateTotalCases()
    {
        yield return new object[] { 1, 9.99m, 9.99m };
        yield return new object[] { 3, 15.00m, 45.00m };
        yield return new object[] { 10, 0.99m, 9.90m };
        yield return new object[] { 1000, 5.00m, 5000.00m };
    }

    // DynamicData source as a property
    private static IEnumerable<object[]> ApplyDiscountEdgeCases => new[]
    {
        new object[] { 0.01m, 0.10m, 0.009m },   // small amount
        new object[] { 9999.99m, 0.25m, 7499.9925m }, // large amount
        new object[] { 0m, 0.50m, 0m },           // zero total
    };
}
```

**Key points:**

- **`[DataRow]`** — best for simple inline values; limited to compile-time constants (no `decimal` literals, so use `double` and cast).
- **`[DynamicData]`** — supports any type including `decimal`; sourced from a static method or property returning `IEnumerable<object[]>`.
- **`[TestInitialize]`** — sets up a fresh instance per test.
- Each test method is focused on one behavior with descriptive naming (`Method_Scenario`).

Add `[ExpectedException(typeof(ArgumentException))]` or `Assert.ThrowsException` tests for invalid inputs (negative quantity, discount > 1, etc.) as needed.
